#include <stdio.h>
#include <string.h>

void nrz_l_encode(char *data, int length, int *signal) {
    /*
     * NRZ-L (Non-Return-to-Zero Level) Encoding
     * Binary 0: High voltage level
     * Binary 1: Low voltage level
     * Signal stays constant for entire bit duration
     */
    for (int i = 0; i < length; i++) {
        // If bit is '0', signal = 1 (positive voltage)
        // If bit is '1', signal = 0 (negative voltage)
        signal[i] = (data[i] == '0') ? 1 : 0;
    }
}

void print_signal(int *signal, int length) {
    printf("Signal: ");
    for (int i = 0; i < length; i++) {
        printf("%d ", signal[i]);
    }
    printf("\n");
}

int main() {
    char data[] = "10110010";
    int length = strlen(data);
    int signal[20];

    printf("Data: %s\n", data);
    nrz_l_encode(data, length, signal);
    print_signal(signal, length);

    return 0;
}
